command.text:
find /workspace -type f -print0 | xargs -0 md5sum | sort | awk '{
    hash=$1; file=$2;
    files[hash] = files[hash] ? files[hash] FS file : file;
    count[hash]++
}
END {
    for (h in count) if (count[h] > 1) {
        split(files[h], arr, FS);
        for (i in arr) print arr[i];
    }
}'

